// logger, usage: log(this, "");
const log = global.get('logger');

// 1.  Input
const minDeltaCents = parseInt(RED.util.getMessageProperty(msg, "dynamic.min_delta_cents")) || 0;
// Per-day caps on the number of LOW / HIGH marks, expressed in hours.
// 0 (or missing/invalid/negative) means no limit.
const cheapestHrs = parseFloat(RED.util.getMessageProperty(msg, "dynamic.cheapest_hrs")) || 0;
const expensiveHrs = parseFloat(RED.util.getMessageProperty(msg, "dynamic.expensive_hrs")) || 0;
const dataAll = RED.util.getMessageProperty(msg, "dynamic.data_all");

if (!dataAll || !Array.isArray(dataAll.list) || dataAll.list.length === 0) {
    log(this, "Price list missing or empty", "warn");
    node.status({ fill: "red", shape: "ring", text: "No price data" });
    return null;
}

const STRATEGY = {
    HIGH: RED.util.getMessageProperty(msg, "dynamic.strategy_expensive") || "Self-consumption",
    LOW: RED.util.getMessageProperty(msg, "dynamic.strategy_cheapest") || "Charge",
    NEUTRAL: RED.util.getMessageProperty(msg, "dynamic.strategy_default") || "Charge PV",
};

// 2.  Build interval timestamps
// Each datapoint covers (hours / datapoints) hours.
const prices = dataAll.list; // cents/kWh — already converted by "Convert price" node
const n = prices.length;
const startTime = new Date(dataAll.start);
const intervalMs = (dataAll.hours / dataAll.datapoints) * 3_600_000;

// 3.  Mark intervals: pair extremes inward — independently per calendar day
//
// Pairing runs separately within each local calendar day, so today's marks
// don't shift when tomorrow's prices arrive. Pair detection is one-to-one
// (each candidate HIGH is matched against one candidate LOW), but the
// per-day cheapest_hrs / expensive_hrs caps may suppress one side of a
// detected pair — so the final marks can be asymmetric (e.g. 2 LOW + 1 HIGH
// in a day if expensive_hrs caps HIGH at 1). The minDelta threshold
// accounts for round-trip efficiency and other losses, so a pair is only
// considered viable when its spread covers the loss.
//
// Method (Extreme-Pair Matching, O(n log n)):
//   1. Sort intervals by price, keep original time-index for re-mapping.
//   2. Two pointers walk inward from the extremes — `lo` from the cheapest
//      unmatched, `hi` from the most-expensive unmatched.
//   3. If the spread between them clears minDelta: mark them, advance both.
//   4. If it does not clear minDelta: the cheapest unmatched LOW paired
//      with the most-expensive unmatched HIGH yields the largest spread
//      still achievable. If even that fails, no remaining pair can satisfy
//      the threshold, so we stop.
//
// This algorithm prefers to mark the truly extreme
// hours (highest-priced as HIGH, lowest-priced as LOW). On well-behaved
// daily curves this produces the same number of pairs as 
// other algorithm variants; but in tight cases it can produce one or two fewer
// pairs. Why choose this version? It marks the price peaks/troughs the user
// would intuitively expect, which is good for user confidence and acceptance of the strategy. It is also efficient and straightforward to implement, without needing complex data structures or backtracking. 
// The main goal is to identify a set of HIGH and LOW intervals that are economically justified by their price spread, while keeping the logic transparent and explainable to the user.

// Note:
// It is up to the user to set minDelta appropriately for their system's efficiency and other costs, to ensure that marked cycles are truly beneficial.
// Also the user can pick strategies that reflect their preferences for what to do during LOW and HIGH intervals, e.g. prioritising self-consumption during HIGH intervals, or selling back to the grid if allowed and profitable.
// This makes optimisation flexible and user-configurable, while still being based on a clear economic rationale.
// However, the algorithm does not attempt to find the optimal global pairing (which would be more complex), but rather a good local pairing that is computationally efficient and easy to understand.

/**
 * @typedef {{ start: Date, end: Date, price: number, mark: 'high'|'low'|null, is_now: boolean }} Interval
 * @type {Interval[]}
 */
const intervals = new Array(n);
for (let i = 0; i < n; i++) {
    const iStart = new Date(startTime.getTime() + i * intervalMs);
    const iEnd = new Date(iStart.getTime() + intervalMs);
    intervals[i] = { start: iStart, end: iEnd, price: prices[i], mark: null, is_now: false };
}

// Group interval indices by local calendar day (key = Y-M-D in local TZ).
const dayBuckets = new Map();
for (let i = 0; i < n; i++) {
    const d = intervals[i].start;
    const key = `${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;
    let bucket = dayBuckets.get(key);
    if (!bucket) { bucket = []; dayBuckets.set(key, bucket); }
    bucket.push(i);
}

// Convert per-day hour caps to per-day interval counts.
// intervalsPerHour = datapoints / hours (e.g. 4 for 15-min intervals).
// 0 hrs => Infinity (no cap). Negatives are treated as 0 (no cap).
const intervalsPerHour = dataAll.datapoints / dataAll.hours;
const maxLowPerDay = cheapestHrs > 0 ? Math.round(cheapestHrs * intervalsPerHour) : Infinity;
const maxHighPerDay = expensiveHrs > 0 ? Math.round(expensiveHrs * intervalsPerHour) : Infinity;

// Per dag de markeringen zetten.
let fullPairCount = 0;   // pairs where BOTH sides were marked (a complete cycle)
let lowMarkCount = 0;    // total LOW marks across all days
let highMarkCount = 0;   // total HIGH marks across all days
for (const dayIndices of dayBuckets.values()) {
    // This day's indices sorted ascending by price (stable on ties).
    const sortedIdx = [...dayIndices].sort((a, b) => prices[a] - prices[b]);
    let lo = 0;
    let hi = sortedIdx.length - 1;
    let lowMarkedToday = 0;
    let highMarkedToday = 0;
    while (lo < hi) {
        const loIdx = sortedIdx[lo];
        const hiIdx = sortedIdx[hi];
        if (prices[hiIdx] - prices[loIdx] >= minDeltaCents) {
            const markLow = lowMarkedToday < maxLowPerDay;
            const markHigh = highMarkedToday < maxHighPerDay;
            // Both caps reached on this day — no more useful work here.
            if (!markLow && !markHigh) break;
            if (markLow) {
                intervals[loIdx].mark = 'low';
                lowMarkedToday++;
                lowMarkCount++;
            }
            if (markHigh) {
                intervals[hiIdx].mark = 'high';
                highMarkedToday++;
                highMarkCount++;
            }
            if (markLow && markHigh) fullPairCount++;
            lo++; hi--;
        } else {
            // sortedIdx[lo] is the cheapest unmatched within this day,
            // sortedIdx[hi] the most-expensive. Their spread is the largest
            // still possible today — if it falls below minDelta, no further
            // pair on this day can satisfy the threshold.
            break;
        }
    }
}

// 4.  Determine current strategy
const now = new Date();
const currentInterval = intervals.find(iv => now >= iv.start && now < iv.end);
if (currentInterval) currentInterval.is_now = true;
const currentMark = currentInterval ? currentInterval.mark : null;

const strategy =
    currentMark === 'high' ? STRATEGY.HIGH :
        currentMark === 'low' ? STRATEGY.LOW :
            STRATEGY.NEUTRAL;

const strategyMark = 
    currentMark === 'high' ? 'Expensive' :
        currentMark === 'low' ? 'Cheap' :
            'Regular';


// 5.  Store results
RED.util.setMessageProperty(msg,"dynamic.data_all.list_marked",intervals,true);
RED.util.setMessageProperty(msg, "dynamic.data_all.mark_now", strategyMark, true);
RED.util.setMessageProperty(msg,"dynamic.strategy",strategy);
flow.set("dynamic_strategy", strategy); // this is the strategy executed when dynamic strategy is active, see the 'Execute' section of this flow.

// 6.  Explain
// Extract and sort marked intervals to pair them correctly for profit analysis
const lowPrices = intervals
    .filter(iv => iv.mark === 'low')
    .map(iv => iv.price)
    .sort((a, b) => a - b); // Cheapest first
const highPrices = intervals
    .filter(iv => iv.mark === 'high')
    .map(iv => iv.price)
    .sort((a, b) => b - a); // Most expensive first

// Only calculate spread over actual completed cycles (pairs)
let grossSpread = 0;
for (let i = 0; i < fullPairCount; i++) {
    grossSpread += (highPrices[i] - lowPrices[i]);
}
const netSpread = grossSpread - (fullPairCount * minDeltaCents);
const markedCount = lowMarkCount + highMarkCount;

// 6a. Average spread per full cycle (pair) today
const avgGrossSpread = fullPairCount > 0 ? Math.round(grossSpread / fullPairCount) : 0;
const avgNetSpread = fullPairCount > 0 ? Math.round(netSpread / fullPairCount) : 0;
RED.util.setMessageProperty(msg, "dynamic.data_all.gross_spread_avg", avgGrossSpread, true);
RED.util.setMessageProperty(msg, "dynamic.data_all.net_spread_avg", avgNetSpread, true);

// 6b.
node.status({
    fill: "blue", shape: "dot",
    text: `${strategy} | ${fullPairCount} cycle${fullPairCount === 1 ? '' : 's'} | net Σ${avgNetSpread}¢`
});
log(this, `Strategy: **${strategy}** | cycles=${fullPairCount} low=${lowMarkCount} high=${highMarkCount} unmarked=${n - markedCount} | gross=${grossSpread}¢ net=${avgNetSpread}¢ minDelta=${minDeltaCents}¢ caps=L${cheapestHrs}h/H${expensiveHrs}h`);

return msg;

